## 🐛 Bug Report

i use exceljs in wxminprogram, when i insert 10 image in a merge cell, it only visiable in ios system , invisiable in android
Lib version: 4.4.0
## Steps To Reproduce

```javascript
async insertImage(workbook, worksheet, cellRange, imagePaths) {
    // 获取合并的单元格信息
    const mergeInfo = worksheet._merges[cellRange];

    if (!mergeInfo) {
      console.log(`单元格 ${cellRange} 不是一个合并单元格。`);
      return;
    }

    const { top, left, bottom, right } = mergeInfo;

    // 计算合并区域的宽度（列宽总和）
    let totalWidth = 0;
    for (let col = left; col <= right; col++) {
      const columnWidth = worksheet.getColumn(col).width || 8.43; // 默认列宽为 8.43
      totalWidth += columnWidth;
    }

    // 计算合并区域的高度（行高总和）
    let totalHeight = 0;
    for (let row = top; row <= bottom; row++) {
      const rowHeight = worksheet.getRow(row).height || 15; // 默认行高为 15
      totalHeight += rowHeight;
    }

    // 将列宽转换为像素（Excel 单元宽度大约为 7.5 像素每单位）
    const totalWidthInPixels = totalWidth * 7.5;

    // 将行高转换为像素（Excel 行高度大约为 15 像素）
    const totalHeightInPixels = totalHeight * 15;

    // 读取并插入图片
    for (let index = 0; index < imagePaths.length; index++) {
      const imagePath = imagePaths[index];

      // 读取图片文件
      const arrayBuffer = wx
        .getFileSystemManager()
        .readFileSync(imagePath.url);
      // const imageData = `data:image/png;base64,${imageBase64}`;
      // 将 ArrayBuffer 转换为 Blob
      // const blob = new Blob([arrayBuffer], { type: 'image/png' }); // 这里以 png 为例，你可以根据数据类型更改

      // 使用 wx.createObjectURL 创建一个临时 URL
      // const image_url = URL.createObjectURL(blob);
      // console.log(imageData)
      // 添加图片到 Excel
      // 获取格式
      const imageId = workbook.addImage({
        // base64: imageData, // 使用 Base64 编码的图片
        buffer: arrayBuffer,
        extension: "png",
      });

      // 计算图片的起始列
      const startCol = left - 1  + (0.2 * (right-left)* (index % 5)) 
      const startRow = top + (0.5 * (bottom-top)* (index % 2))
      //获取图片的宽高
      wx.getImageInfo({
        src: imagePath.url,
        success: function (res) {
          console.log("图片信息：", res);
          let imageWidth = res.width;
          let imageHeight = res.height;
          // 如果宽度放不下五个
          const imageMaxWidth = totalWidthInPixels / 5;
          //等比例缩小
          if (imageWidth > imageMaxWidth) {
            imageWidth = imageMaxWidth;
            imageHeight = (imageWidth / imageHeight) * imageHeight;
          }
          // 如果高度不放下两个
          const imageMaxHeight = totalHeightInPixels / 2;
          if (imageHeight > imageMaxHeight) {
            imageHeight = imageMaxHeight;
            imageWidth = (imageHeight / imageWidth) * imageWidth;
          }
          console.log("imageId===>",imageId)
          worksheet.addImage(imageId, {
            tl: { col: startCol, row: startRow }, // 起始位置 (左上角)
            ext: { width: imageWidth, height: imageHeight }, // 确保宽高一致
          });
        },
        fail: function (err) {
          console.log("获取图片信息失败：", err);
        },
      })
    }
  },
```

